INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1922, 207987, 10, 2224, '不愿做瘸子', '郭敬明在《爱与痛的边缘》里有一篇《七月里的左右手》，写的是关于文理分科的事。他说，文科如我的左手，理科是我的右手，我靠左手吃饭，靠右手写字，老师问我你读文还是读理啊？我感觉他是在问你是砍掉左手好还是右手好呢？我听见自己心碎的声音。
<br>我又何尝不如此，我却觉得文理是我的左右腿，我长这么大，一直靠它们共同支撑着，很坚实，我站得很稳。我一直在想它们一定会一直伴随我一生。然而现在却要我截掉一只，我于心何忍，那我以后如何在人生的道路上走下去，我不是成为一个名副其实的瘸子了吗？我听见自己心迸裂的声音。
<br>我实在不能忍受，为了应战高考，我们不得不放弃一条腿，好好保养另一条，然而考上大学后，我们却是只有一条像样的腿，另一条已被摧残得面目全非、惨不忍睹了，就算重植，也永远抹不去那深深的伤痕。我们依然只是瘸子，艰难地向前行走了，拄着“文凭”粘成的拐杖――那根实在不坚实，随时易折断的软木。
<br>我无奈，只得听命刽子手的安排，准备眼睁睁地看着我心爱的一条腿离开。然而我却一直在徘徊。是的。我怎么舍得呢？掌心手背都是肉，我的左右腿，陪着我走过风风雨雨的我亲爱的左右腿，我怎么决定得了呢？刽子手啊！你不知道你把这仅有的选择权交给我自己，是更残忍的行为啊！既然无法选择保留，那何必呢？你随便斩吧！
<br>我欲哭无泪。为我们的无辜。', '郭敬明在《爱与痛的边缘》里有一篇《七月里的左右手》，写的是关于文理分科的事。他说，文科如我的左手，理科是我的右手，我靠左手吃饭，靠右手写字，老师问我你读文还是读理啊？我感觉他是在问你是砍掉左手好还是右手好呢？我听见自己心碎的声音。

我又何尝不如此，我却觉得文理是我的左右腿，我长这么大，一直靠它们共同支撑着，很坚实，我站得很稳。我一直在想它们一定会一直伴随我一生。然而现在却要我截掉一只，我于心何忍，那我以后如何在人生的道路上走下去，我不是成为一个名副其实的瘸子了吗？我听见自己心迸裂的声音。

我实在不能忍受，为了应战高考，我们不得不放弃一条腿，好好保养另一条，然而考上大学后，我们却是只有一条像样的腿，另一条已被摧残得面目全非、惨不忍睹了，就算重植，也永远抹不去那深深的伤痕。我们依然只是瘸子，艰难地向前行走了，拄着“文凭”粘成的拐杖――那根实在不坚实，随时易折断的软木。

我无奈，只得听命刽子手的安排，准备眼睁睁地看着我心爱的一条腿离开。然而我却一直在徘徊。是的。我怎么舍得呢？掌心手背都是肉，我的左右腿，陪着我走过风风雨雨的我亲爱的左右腿，我怎么决定得了呢？刽子手啊！你不知道你把这仅有的选择权交给我自己，是更残忍的行为啊！既然无法选择保留，那何必呢？你随便斩吧！

我欲哭无泪。为我们的无辜。', '我偶尔是透明的', '2003-07-08 23:34:00', 8, '20030721055727_bbsid_207987_board_10_7818017633.html', '20030721055727');
